#!/bin/bash
# Daniel

saludar() {
    read -p "¿Cómo te llamas? " nombre
    echo "Hola, $nombre. ¡Bienvenido!"
}

mostrar_fecha() {
    echo "Fecha actual: $(date +"%A, %d de %B de %Y - %H:%M:%S")"
}

uso_disco() {
    echo "--- Uso de disco ---"
    df -h
}

menu_principal() {
    local opcion=0
    while [ $opcion -ne 4 ]; do
        echo ""
        echo "====MENÚ==="
        echo "1. Saludar"
        echo "2. Mostrar fecha"
        echo "3. Uso de disco"
        echo "4. Salir"
        read -p "Elige una opción: " opcion

        case $opcion in
            1) saludar ;;
            2) mostrar_fecha ;;
            3) uso_disco ;;
            4) echo "Saliendo..." ;;
            *) echo "Opción no válida" ;;
        esac
    done
}

menu_principal
